import { Component, EventEmitter, Input, Output, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';

export interface ReportPayload {
  reason: string;
  detail: string;
}

/** Report a member. Deep-linkable via `?modal=report` on a profile route. */
@Component({
  selector: 'app-report-modal',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './report-modal.component.html',
  styleUrl: './report-modal.component.css',
})
export class ReportModalComponent {
  @Input() targetName = 'this member';
  @Output() submitted = new EventEmitter<ReportPayload>();
  @Output() dismiss = new EventEmitter<void>();

  readonly reasons = [
    'Inappropriate photos',
    'Fake or impersonated profile',
    'Harassment or abusive messages',
    'Spam or solicitation',
    'Off-platform / scam behaviour',
    'Other',
  ];

  readonly reason = signal<string>('');
  readonly detail = signal<string>('');
  readonly done = signal(false);

  submit(): void {
    if (!this.reason()) return;
    this.done.set(true);
    this.submitted.emit({ reason: this.reason(), detail: this.detail() });
  }
}
